defmodule RawSqlApp do
  @moduledoc "Executes raw SQL queries with string interpolation."

  alias RawSqlApp.Repo
  import Ecto.Adapters.SQL

  def run do
    IO.puts "Enter the role to filter users by (e.g., 'admin', 'editor', 'viewer'):"
    role = IO.gets("") |> String.trim()

    sql_query = "SELECT id, name, role FROM users WHERE role = '#{role}'"

    IO.puts "\nExecuting SQL query: #{sql_query}"

    case query(Repo, sql_query) do
      {:ok, %{rows: rows, columns: columns}} ->
        if Enum.empty?(rows) do
          IO.puts "No users found for role: '#{role}'"
        else
          IO.puts "Found users:"
          rows
          |> Enum.each(fn row ->
            user_data = Enum.zip(columns, row) |> Map.new()
            IO.inspect user_data
          end)
        end

      {:error, reason} ->
        IO.puts "Error executing query: #{inspect reason}"
    end

    :ok
  end
